import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef, type ComponentRef } from 'react';
import { CloseIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './CloseButton.module.css';

type CloseButtonRootProps = HTMLArkProps<'button'> & {
  'data-disabled'?: string;
  'data-part'?: string;
  'data-scope'?: string;
  'data-slot'?: string;
};

const CloseButtonRoot = forwardRef<ComponentRef<typeof ark.button>, CloseButtonRootProps>(
  function CloseButtonRoot(
    {
      asChild,
      className,
      children,
      disabled,
      onClick,
      type,
      'aria-disabled': ariaDisabled,
      'aria-label': ariaLabel,
      'aria-labelledby': ariaLabelledBy,
      'data-disabled': dataDisabled,
      'data-part': dataPart,
      'data-scope': dataScope,
      'data-slot': dataSlot,
      ...props
    },
    ref,
  ) {
    const isDisabled =
      disabled || ariaDisabled === true || ariaDisabled === 'true' || dataDisabled !== undefined;
    const handleClick: CloseButtonRootProps['onClick'] = (event) => {
      if (isDisabled) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }

      onClick?.(event);
    };

    return (
      <ark.button
        ref={ref}
        asChild={asChild}
        {...props}
        type={asChild ? type : (type ?? 'button')}
        disabled={disabled}
        data-scope={dataScope ?? 'close-button'}
        data-part={dataPart ?? 'root'}
        data-slot={dataSlot ?? 'close-button-root'}
        data-disabled={dataDisabled ?? (isDisabled ? '' : undefined)}
        className={clsx(styles.root, normalizeClassName(className))}
        aria-disabled={ariaDisabled}
        aria-label={ariaLabel ?? (children == null && ariaLabelledBy == null ? 'Close' : undefined)}
        aria-labelledby={ariaLabelledBy}
        onClick={handleClick}
      >
        {children ?? <CloseIcon />}
      </ark.button>
    );
  },
);

const CloseButton = Object.assign(CloseButtonRoot, {
  Root: CloseButtonRoot,
});

export { CloseButton };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: var(--moduix-close-button-size, var(--moduix-spacing-7));
    height: var(--moduix-close-button-size, var(--moduix-spacing-7));
    margin: 0;
    padding: 0;
    border: none;
    background-color: var(--moduix-close-button-bg, transparent);
    border-radius: var(--moduix-close-button-radius, var(--moduix-radius-sm));
    color: var(--moduix-close-button-color, var(--moduix-color-muted-foreground));
    appearance: none;
    font: inherit;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-close-button-transition, var(--moduix-transition-default)),
      color var(--moduix-close-button-transition, var(--moduix-transition-default)),
      opacity var(--moduix-close-button-transition, var(--moduix-transition-default));

    & > svg {
      flex-shrink: 0;
      width: var(--moduix-close-button-icon-size, var(--moduix-spacing-3));
      height: var(--moduix-close-button-icon-size, var(--moduix-spacing-3));
    }

    @media (hover: hover) {
      &:hover:not([data-disabled]) {
        background-color: var(--moduix-close-button-bg-hover, var(--moduix-color-muted));
        color: var(--moduix-close-button-color-hover, var(--moduix-color-foreground));
      }
    }

    &:focus-visible {
      outline: var(
          --moduix-close-button-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-close-button-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-close-button-focus-ring-offset, var(--moduix-focus-ring-offset));
    }

    &[data-disabled] {
      cursor: default;
      pointer-events: none;
      opacity: var(--moduix-close-button-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }
}
